return await space.current.patchWidget("snake-game", {
  edits: [
    {
      path: "renderer",
      op: "replace",
      value: async function (parent) {
        parent.innerHTML = `
          <style>
            .snake-wrap {
              position: relative;
              width: 100%;
              height: 100%;
              background: #111;
              overflow: hidden;
              display: flex;
              align-items: center;
              justify-content: center;
            }
            canvas {
              width: 100%;
              height: 100%;
              display: block;
              image-rendering: pixelated;
            }
          </style>
          <div class="snake-wrap"><canvas id="snake-canvas"></canvas></div>
        `

        const canvas = parent.querySelector("#snake-canvas")
        const ctx = canvas.getContext("2d")

        const gridSize = 20
        const cols = 20
        const rows = 20
        const dpr = window.devicePixelRatio || 1

        let cell = 24
        let width = 0
        let height = 0

        const resize = () => {
          const rect = parent.getBoundingClientRect()
          width = rect.width
          height = rect.height
          canvas.width = Math.max(1, Math.floor(width * dpr))
          canvas.height = Math.max(1, Math.floor(height * dpr))
          canvas.style.width = `${width}px`
          canvas.style.height = `${height}px`
          ctx.setTransform(dpr, 0, 0, dpr, 0, 0)
          cell = Math.floor(Math.min(width / cols, height / rows))
        }

        resize()
        new ResizeObserver(resize).observe(parent)

        let snake = [
          { x: 10, y: 10 },
          { x: 9, y: 10 },
          { x: 8, y: 10 }
        ]
        let prevSnake = snake.map(p => ({ ...p }))
        let dir = { x: 1, y: 0 }
        let nextDir = { x: 1, y: 0 }
        let food = { x: 14, y: 10 }
        let score = 0
        let lastStep = performance.now()
        const stepMs = 140

        const randCell = () => ({
          x: Math.floor(Math.random() * cols),
          y: Math.floor(Math.random() * rows)
        })

        const same = (a, b) => a.x === b.x && a.y === b.y

        const placeFood = () => {
          let candidate
          do {
            candidate = randCell()
          } while (snake.some(s => same(s, candidate)))
          food = candidate
        }

        const lerp = (a, b, t) => a + (b - a) * t
        const ease = t => t * t * (3 - 2 * t)

        const update = () => {
          const now = performance.now()
          const elapsed = now - lastStep
          if (elapsed < stepMs) return elapsed / stepMs

          lastStep = now
          dir = nextDir

          prevSnake = snake.map(p => ({ ...p }))
          const head = { x: snake[0].x + dir.x, y: snake[0].y + dir.y }

          if (head.x < 0) head.x = cols - 1
          if (head.x >= cols) head.x = 0
          if (head.y < 0) head.y = rows - 1
          if (head.y >= rows) head.y = 0

          if (snake.some((s, i) => i !== snake.length - 1 && same(s, head))) {
            snake = [
              { x: 10, y: 10 },
              { x: 9, y: 10 },
              { x: 8, y: 10 }
            ]
            prevSnake = snake.map(p => ({ ...p }))
            dir = { x: 1, y: 0 }
            nextDir = { x: 1, y: 0 }
            score = 0
            placeFood()
            return 0
          }

          snake.unshift(head)
          if (same(head, food)) {
            score++
            placeFood()
          } else {
            snake.pop()
          }

          return 0
        }

        const drawRoundRect = (x, y, w, h, r, fill) => {
          ctx.beginPath()
          ctx.moveTo(x + r, y)
          ctx.arcTo(x + w, y, x + w, y + h, r)
          ctx.arcTo(x + w, y + h, x, y + h, r)
          ctx.arcTo(x, y + h, x, y, r)
          ctx.arcTo(x, y, x + w, y, r)
          ctx.closePath()
          ctx.fillStyle = fill
          ctx.fill()
        }

        const frame = () => {
          const t = ease(update() || 0)
          ctx.clearRect(0, 0, width, height)
          ctx.fillStyle = "#101010"
          ctx.fillRect(0, 0, width, height)

          const offsetX = Math.floor((width - cols * cell) / 2)
          const offsetY = Math.floor((height - rows * cell) / 2)

          for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
              ctx.fillStyle = ((x + y) % 2 === 0) ? "#181818" : "#151515"
              ctx.fillRect(offsetX + x * cell, offsetY + y * cell, cell, cell)
            }
          }

          ctx.fillStyle = "#e74c3c"
          drawRoundRect(
            offsetX + food.x * cell + cell * 0.2,
            offsetY + food.y * cell + cell * 0.2,
            cell * 0.6,
            cell * 0.6,
            cell * 0.2,
            "#e74c3c"
          )

          for (let i = snake.length - 1; i >= 0; i--) {
            const cur = snake[i]
            const prev = prevSnake[i] || cur
            const px = lerp(prev.x, cur.x, t)
            const py = lerp(prev.y, cur.y, t)
            const grow = i === 0 ? 0.08 : 0.12

            const x = offsetX + px * cell + cell * grow
            const y = offsetY + py * cell + cell * grow
            const size = cell * (1 - grow * 2)

            ctx.fillStyle = i === 0 ? "#5dff7a" : "#2ecc71"
            drawRoundRect(x, y, size, size, cell * 0.22, ctx.fillStyle)
          }

          ctx.fillStyle = "rgba(255,255,255,0.85)"
          ctx.font = "14px sans-serif"
          ctx.fillText(`Score: ${score}`, 10, 20)

          requestAnimationFrame(frame)
        }

        placeFood()
        requestAnimationFrame(frame)

        const handleKey = e => {
          const k = e.key
          if (k === "ArrowUp" && dir.y !== 1) nextDir = { x: 0, y: -1 }
          if (k === "ArrowDown" && dir.y !== -1) nextDir = { x: 0, y: 1 }
          if (k === "ArrowLeft" && dir.x !== 1) nextDir = { x: -1, y: 0 }
          if (k === "ArrowRight" && dir.x !== -1) nextDir = { x: 1, y: 0 }
        }

        window.addEventListener("keydown", handleKey)
      }
    }
  ]
})

